# test_interleave.py
import pytest

from your_module import interleave


class TestInterleave:
    def test_happy_path_equal_length(self):
        assert interleave([1, 2, 3], ["a", "b", "c"]) == [1, "a", 2, "b", 3, "c"]

    def test_happy_path_a_longer(self):
        assert interleave([1, 2, 3, 4], ["a", "b"]) == [1, "a", 2, "b", 3, 4]

    def test_happy_path_b_longer(self):
        assert interleave([1, 2], ["a", "b", "c"]) == [1, "a", 2, "b", "c"]

    def test_happy_path_with_empty_a(self):
        assert interleave([], ["a", "b"]) == ["a", "b"]

    def test_happy_path_with_empty_b(self):
        assert interleave([1, 2], []) == [1, 2]

    def test_happy_path_both_empty(self):
        assert interleave([], []) == []

    def test_edge_cases_with_duplicates_and_none(self):
        a = [None, 1, 1]
        b = [1, None]
        assert interleave(a, b) == [None, 1, 1, None, 1]

    def test_edge_cases_with_mismatched_types_allowed(self):
        assert interleave([True, 2], ["x", "y", "z"]) == [True, "x", 2, "y", "z"]

    def test_error_non_list_inputs_raise_type_error_on_len(self):
        # Function expects list-like supporting len and slicing.
        with pytest.raises(TypeError):
            interleave(None, [1, 2])

        with pytest.raises(TypeError):
            interleave([1, 2], None)

    def test_error_non_sized_iterable_raise_type_error(self):
        # len() will fail for generators.
        gen = (x for x in [1, 2, 3])
        with pytest.raises(TypeError):
            interleave(gen, ["a", "b"])

    def test_error_objects_without_len_raise_type_error(self):
        class NoLen:
            pass

        with pytest.raises(TypeError):
            interleave(NoLen(), [1])

        with pytest.raises(TypeError):
            interleave([1], NoLen())
